import { hasPermissionCode } from '../utils/erpPermissionCode';

const PREFIX = 'erp-supply:purchasing:requests';

export function useYcmhPermissions() {
  const canWrite = hasPermissionCode(`${PREFIX}:write`);
  return {
    canRead: hasPermissionCode(`${PREFIX}:read`),
    canWrite,
    canCreate: canWrite,
    canApprove: hasPermissionCode(`${PREFIX}:approve`),
  };
}
